data class AuthRequest(val uri: Uri, val state: String)

class OAuthContract : ActivityResultContract<AuthRequest, Uri?>() {
    override fun createIntent(context: Context, input: AuthRequest): Intent {
        return Intent(context, OAuthCustomTabActivity::class.java).apply {
            putExtra(OAuthCustomTabActivity.EXTRA_URI, input.uri.toString())
            putExtra(OAuthCustomTabActivity.EXTRA_STATE, input.state)
        }
    }

    override fun parseResult(resultCode: Int, intent: Intent?): Uri? {
        if (resultCode != Activity.RESULT_OK) return null
        val uriStr = intent?.getStringExtra(OAuthCustomTabActivity.EXTRA_RESULT_URI) ?: return null
        return Uri.parse(uriStr)
    }
}

class OAuthCustomTabActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val uri = intent.getStringExtra(EXTRA_URI)?.let(Uri::parse)
        if (uri == null) {
            setResult(Activity.RESULT_CANCELED)
            finish()
            return
        }

        if (savedInstanceState == null) {
            CustomTabsIntent.Builder().build().launchUrl(this, uri)
        }
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
    }

    override fun onResume() {
        super.onResume()
        val data = intent?.data
        if (data != null && isOurRedirect(data)) {
            setResult(Activity.RESULT_OK, Intent().putExtra(EXTRA_RESULT_URI, data.toString()))
            finish()
            return
        }
        // If user backed out or tab was closed, we may come back without a redirect.
        // We'll treat it as cancelled once the activity is resumed again.
        if (intent?.getBooleanExtra(EXTRA_ALREADY_RESUMED, false) == true) {
            setResult(Activity.RESULT_CANCELED)
            finish()
        } else {
            intent?.putExtra(EXTRA_ALREADY_RESUMED, true)
        }
    }

    private fun isOurRedirect(uri: Uri): Boolean {
        return uri.scheme == SocialLoginConfig.REDIRECT_SCHEME &&
            uri.host == SocialLoginConfig.REDIRECT_HOST &&
            uri.path == SocialLoginConfig.REDIRECT_PATH
    }

    companion object {
        const val EXTRA_URI = "extra_uri"
        const val EXTRA_STATE = "extra_state"
        const val EXTRA_RESULT_URI = "extra_result_uri"
        const val EXTRA_ALREADY_RESUMED = "extra_already_resumed"
    }
}

object OAuthCallbackRegistry {
    private val pending = mutableMapOf<String, CompletableDeferred<Uri?>>()

    fun await(state: String): CompletableDeferred<Uri?> {
        val d = CompletableDeferred<Uri?>()
        pending[state] = d
        return d
    }

    fun deliver(uri: Uri?) {
        if (uri == null) return
        val state = uri.getQueryParameter("state") ?: return
        pending.remove(state)?.complete(uri)
    }
}

object Pkce {
    fun generateCodeVerifier(): String {
        val chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-._~"
        val sb = StringBuilder()
        val len = 64
        val rnd = java.security.SecureRandom()
        repeat(len) { sb.append(chars[rnd.nextInt(chars.length)]) }
        return sb.toString()
    }

    fun codeChallenge(verifier: String): String {
        val md = MessageDigest.getInstance("SHA-256").digest(verifier.toByteArray(Charsets.US_ASCII))
        return base64UrlNoPad(md)
    }

    private fun base64UrlNoPad(bytes: ByteArray): String {
        return android.util.Base64.encodeToString(bytes, android.util.Base64.URL_SAFE or android.util.Base64.NO_WRAP or android.util.Base64.NO_PADDING)
    }
}

